python3 -c "
import json
d=json.load(open('/mnt/session/outputs/postmortem.json'))
assert set(d.keys()) >= {'timeline','hypotheses','root_cause_idx','patch_proposal'}
for ev in d['timeline']:
    assert set(ev.keys())=={'t_ns','label','cross_view'}, ev.keys()
    assert isinstance(ev['t_ns'], int)
    assert isinstance(ev['cross_view'], bool)
for h in d['hypotheses']:
    assert set(h.keys())=={'bug_class','confidence','summary','evidence','patch_hint'}
    assert h['bug_class'] in {'pid_saturation','sensor_timeout','state_machine_deadlock','bad_gain_tuning','missing_null_check','calibration_drift','latency_spike','other'}, h['bug_class']
    assert 0<=h['confidence']<=1
    for e in h['evidence']:
        assert set(e.keys())=={'source','topic_or_file','t_ns','snippet'}
        assert e['source'] in {'camera','telemetry','code','timeline'}
print('schema OK')
print('timeline count:', len(d['timeline']))
print('hypothesis count:', len(d['hypotheses']))
print('root_cause_idx:', d['root_cause_idx'])
print('bug_classes:', [h['bug_class'] for h in d['hypotheses']])
print('confidences:', [h['confidence'] for h in d['hypotheses']])
"
